import flydsl.compiler as flyc
import flydsl.expr as fx
from flydsl.expr import arith, buffer_ops, const_expr, gpu, range_constexpr
from flydsl.expr.typing import T


@flyc.kernel
def my_kernel(
    A: fx.Tensor, B: fx.Tensor, C: fx.Tensor, N: fx.Int32, M: fx.Int32
):
    bid = gpu.block_id("blockIdx.x")
    tid = gpu.thread_id("threadIdx.x")

    lds = fx.SharedAllocator(gpu.block_dim("blockIdx.x") * 4, fx.Float32)
    lds_ptr = lds.alloc(N)

    for i in range_constexpr(0, M, 4):
        val = A[bid * M + tid + i]
        lds_ptr[tid + i] = val

    gpu.syncthreads()

    for i in range_constexpr(0, N, 4):
        val = lds_ptr[tid + i]
        C[bid * N + tid + i] = val * B[tid + i]


@flyc.jit
def my_jit(A: fx.Tensor, B: fx.Tensor, C: fx.Tensor, N: fx.Int32, M: fx.Int32):
    return my_kernel(A, B, C, N, M)

import flydsl.compiler as flyc
