from flydsl.expr import arith, buffer_ops, const_expr, gpu, range_constexpr, rocdl, vector
from flydsl.utils.smem_allocator import SmemAllocator


@flyc.kernel
def softmax_normalization(
    input: fx.Tensor,
    output: fx.Tensor,
    num_elements: fx.Int32,
    tile_size: fx.Int32,
):
    bid = gpu.block_id_x()
    tid = gpu.thread_id_x()
    num_tiles = arith.ceildiv(num_elements, tile_size)

    shared_mem = SmemAllocator().alloc(num_elements, fx.Float32)
    smem_ptr = buffer_ops.get_pointer(shared_mem, fx.Float32)

    for tile_idx in range_constexpr(0, num_tiles):
        start_idx = tile_idx * tile_size
        end_idx = const_expr.min((tile_idx + 1) * tile_size, num_elements)

        for i in range_constexpr(0, tile_size):
            global_idx = start_idx + i
            if global_idx < end_idx:
                shared_mem[tid * tile_size + i] = input[global_idx]

        gpu.syncthreads()

        sum = 0.0
        for i in range_constexpr(0, tile_size):
            sum += shared_mem[tid * tile_size + i]

        for i in range_constexpr(0, tile_size):
            global_idx = start_idx + i
            if global_idx < end_idx:
                output[global_idx] = shared_mem[tid * tile_size + i] / sum

        gpu.syncthreads()


@flyc.jit
def softmax_launch(input, output, num_elements, tile_size):
    grid = (num_elements + tile_size - 1) // tile_size
    softmax_normalization[(1, 1, grid), (1, 1, tile_size)](
        input, output, num_elements, tile_size
    )

