import flydsl.compiler as flyc
import flydsl.expr as fx

@flyc.kernel
def softmax_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    N: fx.Constexpr[int],
    M: fx.Constexpr[int],
):
    tid = fx.thread_idx.x
    bid = fx.block_idx.x
    cta_id = bid // 128
    warp_id = bid % 128
    lane_id = tid % 32

    smem_allocator = fx.SmemAllocator()
    smem = smem_allocator.alloc((128, 32), fx.float32)
    smem_allocator.commit()

    for i in range(0, N, 128):
        global_offset = i + cta_id * 128
        if global_offset < N:
            local_offset = global_offset % 128
            smem[local_offset, lane_id] = A[global_offset, warp_id * 32 + lane_id]
        else:
            smem[local_offset, lane_id] = 0.0

    fx.block_sync()

    for i in range(1, 32):
        if lane_id >= i:
            smem[local_offset, lane_id] += smem[local_offset, lane_id - i]

    fx.block_sync()

    if lane_id == 31:
        smem[local_offset, 31] = 0.0

    fx.block_sync()

    for i in range(1, 32):
        if lane_id >= i:
            smem[local_offset, lane_id] -= smem[local_offset, lane_id - i]

    fx.block_sync()

    if global_offset < N:
        B[global_offset, warp_id * 32 + lane_id] = fx.exp(smem[local_offset, lane_id])

