@flyc.kernel
def softmax_kernel(
    input: fx.Tensor,
    output: fx.Tensor,
    n: fx.Int32,
    softmax_temp: fx.Float32,
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    smem = fx.SmemAllocator().alloc(fx.Float32, 256, 256)
    mma_frag = fx.MmaFragment(fx.Float32, 16, 16, 16, 4)
    swizzle = fx.Swizzle4()

    @flyc.stage
    def stage_load():
        for i in range(16):
            smem[bid, tid + i * 16] = input[bid, tid + i * 16]

    @flyc.stage
    def stage_reduce():
        acc = fx.Float32(0.0)
        for i in range(16):
            acc += smem[bid, tid + i * 16]
        return acc

    @flyc.stage
    def stage_normalize():
        acc = stage_reduce()
        acc /= n * softmax_temp
        for i in range(16):
            smem[bid, tid + i * 16] = fx.exp(smem[bid, tid + i * 16] - acc)

    @flyc.stage
    def stage_store():
        for i in range(16):
            output[bid, tid + i * 16] = smem[bid, tid + i * 16]

    flyc.pipeline(
        stage_load,
        stage_reduce,
        stage_normalize,
        stage_store,
    )

