@flyc.kernel
def softmax_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    N: fx.Constexpr[int],
    BLOCK_SIZE: fx.Constexpr[int],
    TILE_SIZE: fx.Constexpr[int],
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x

    smem = fx.SharedAllocator()
    sA = smem.buffer((BLOCK_SIZE,), fx.float32)
    smem.commit()

    for tile_idx in range(0, N, TILE_SIZE):
        idx = bid * TILE_SIZE + tile_idx + tid
        if idx < N:
            sA[tid] = A[idx]
        fx.barrier(fx.ComputeScope.Block)

        exp_sum = fx.float32(0.0)
        for i in range(BLOCK_SIZE):
            exp_sum += fx.exp(sA[i])
        fx.barrier(fx.ComputeScope.Block)

        if idx < N:
            B[idx] = fx.exp(sA[tid]) / exp_sum


