import flydsl.compiler as flyc
import flydsl.expr as fx


@flyc.kernel
def softmax_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    N: fx.Constexpr[int],
    M: fx.Constexpr[int],
):
    tid = fx.thread_idx.x
    bid = fx.block_idx.x
    smem = fx.SharedAllocator()
    tile_size = 16
    num_tiles = N // tile_size
    tile_idx = bid * tile_size

    A_tile = smem.alloc((tile_size, M), fx.float32)
    B_tile = smem.alloc((tile_size, M), fx.float32)

    for i in range(tile_idx, tile_idx + tile_size):
        for j in range(M):
            A_tile[i % tile_size, j] = A[i, j]

    max_val = fx.Reduce(max)(A_tile, fx.Axis(1))
    exp_sum = fx.Reduce(sum)(fx.exp(A_tile - max_val), fx.Axis(1))

    for i in range(tile_idx, tile_idx + tile_size):
        for j in range(M):
            B_tile[i % tile_size, j] = fx.exp(A_tile[i % tile_size, j] - max_val[i]) / exp_sum[i]

    for i in range(tile_idx, tile_idx + tile_size):
        for j in range(M):
            B[i, j] = B_tile[i % tile_size, j]


@flyc.jit
def softmax(A: fx.Tensor, N: fx.Constexpr[int], M: fx.Constexpr[int]):
    B = fx.Tensor(A.shape, fx.float32)
    softmax_kernel.launch(grid=(N // 16,), block=(256,), args=(A, B, N, M))
    return B


