import flydsl.compiler as flyc
import flydsl.expr as fx

THREADS = 256


@flyc.kernel
def softmax_kernel(
    x: fx.Tensor,
    y: fx.Tensor,
    N: fx.Constexpr[int],
    M: fx.Constexpr[int],
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    smem = flyc.SmemAllocator().alloc((M,), fx.float32)
    for j in range(M):
        smem[j] = fx.float32(0.0)
    fx.barrier(fx.scope.block)
    for i in fx.block_range(0, N, THREADS):
        if i + tid < N:
            val = fx.load(x, bid * N + i + tid)
            smem[tid] = fx.max(smem[tid], val)
    fx.barrier(fx.scope.block)
    max_val = smem[0]
    for j in range(M):
        max_val = fx.max(max_val, smem[j])
    fx.barrier(fx.scope.block)
    sum_exp = fx.float32(0.0)
    for i in fx.block_range(0, N, THREADS):
        if i + tid < N:
            val = fx.load(x, bid * N + i + tid)
            exp_val = fx.exp(val - max_val)
            smem[tid] = exp_val
            sum_exp += exp_val
    fx.barrier(fx.scope.block)
    for i in fx.block_range(0, N, THREADS):
        if i + tid < N:
            val = smem[tid]
            y[i + tid] = val / sum_exp


@flyc.kernel
def softmax_backward_kernel(
    dy: fx.Tensor,
    y: fx.Tensor,
    dx: fx.Tensor,
    N: fx.Constexpr[int],
    M: fx.Constexpr[int],
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    smem = flyc.SmemAllocator().alloc((M,), fx.float32)
    sum_dy = fx.float32(0.0)
    for i in fx.block_range(0, N, THREADS):
        if i + tid < N:
            val = fx.load(dy, bid * N + i + tid)
            smem[tid] = val
            sum_dy += val
    fx.barrier(fx.scope.block)
    for i in fx.block_range(0, N, THREADS):
        if i + tid < N:
            val = fx.load(y, bid * N + i + tid)
            dx[i + tid] = val * (smem[tid] - sum_dy)

