import flydsl.expr as fx
import torch


@flyc.jit
def _rope_kernel(
    v: fx.Tensor,
    cos: fx.Tensor,
    sin: fx.Tensor,
    block_dim: fx.Constexpr[int],
    head_size: fx.Constexpr[int],
):
    v_block = v.tile({
        "k": block_dim,
        "head": head_size,
    })
    cos_block = cos.tile({
        "k": block_dim,
        "head": head_size,
    })
    sin_block = sin.tile({
        "k": block_dim,
        "head": head_size,
    })

    v_block = v_block.permute({
        "k": "k",
        "head": "head",
    })
    cos_block = cos_block.permute({
        "k": "k",
        "head": "head",
    })
    sin_block = sin_block.permute({
        "k": "k",
        "head": "head",
    })

    v_block = v_block.broadcast({
        "head": head_size,
    })
    cos_block = cos_block.broadcast({
        "head": head_size,
    })
    sin_block = sin_block.broadcast({
        "head": head_size,
    })

    v_block = v_block * cos_block + v_block * sin_block

    return v_block


@flyc.kernel
def rope_kernel(
    v: fx.Tensor,
    cos: fx.Tensor,
    sin: fx.Tensor,
    block_dim: fx.Constexpr[int],
    head_size: fx.Constexpr[int],
):
    v_block = _rope_kernel(v, cos, sin, block_dim, head_size)
    return v_block


def rope(v: torch.Tensor, cos: torch.Tensor, sin: torch.Tensor, block_dim: int, head_size: int):
    v_fx = fx.from_torch(v)
    cos_fx = fx.from_torch(cos)
    sin_fx = fx.from_torch(sin)
    block_dim_fx = fx.Constexpr(block_dim)
    head_size_fx = fx.Constexpr(head_size)

    v_block = rope_kernel(v_fx, cos_fx, sin_fx, block_dim_fx, head_size_fx)
    return v_block.to_torch(v)

