from flydsl.utils.smem_allocator import SmemAllocator


@flyc.kernel
def quantize_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    C: fx.Tensor,
    M: fx.Int32,
    N: fx.Int32,
    K: fx.Int32,
):
    bid = gpu.block_id()
    tid = gpu.thread_id()
    smem = SmemAllocator()

    def load_tile(src, dst, tile_size):
        for i in range_constexpr(0, tile_size):
            dst[i] = src[i]

    def store_tile(src, dst, tile_size):
        for i in range_constexpr(0, tile_size):
            dst[i] = src[i]

    def quantize_tile(tile, tile_size):
        for i in range_constexpr(0, tile_size):
            tile[i] = arith.round_nearest_even(tile[i] * 127.0)

    def mfma_tile(a, b, c, tile_size):
        for i in range_constexpr(0, tile_size):
            c[i] = rocdl.mfma_f32_32x32x32_f32(a[i], b[i], c[i])

    A_local = smem.alloc((32, 32), fx.Float32)
    B_local = smem.alloc((32, 32), fx.Float32)
    C_local = smem.alloc((32, 32), fx.Float32)

    row = bid * 32
    col = tid * 32
    tile = fx.Tensor((32, 32), fx.Float32)

    for i in range_constexpr(0, 32):
        for j in range_constexpr(0, 32):
            tile[i, j] = A[row + i, col + j]

    quantize_tile(tile, 32 * 32)

    for i in range_constexpr(0, 32):
        for j in range_constexpr(0, 32):
            A_local[i, j] = tile[i, j]

    for k in range_constexpr(0, K):
        for i in range_constexpr(0, 32):
            for j in range_constexpr(0, 32):
                B_local[i, j] = B[row + i, k * 32 + j]

        mfma_tile(A_local, B_local, C_local, 32 * 32)

    for i in range_constexpr(0, 32):
        for j in range_constexpr(0, 32):
            C[row + i, col + j] = C_local[i, j]


