import math

import flydsl.compiler as flyc
import flydsl.expr as fx


@flyc.kernel
def softmax_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    m: fx.Constexpr[int],
    n: fx.Constexpr[int],
    block_dim_x: fx.Constexpr[int],
    block_dim_y: fx.Constexpr[int],
):
    tid = fx.thread_idx.x
    bid = fx.block_idx.x
    bdim = fx.block_dim.x

    smem = fx.SmemAllocator()
    smem_A = smem.alloc((block_dim_y, block_dim_x), fx.Float32)

    # Load tile of data from global memory to shared memory
    for y in range(0, block_dim_y, 16):
        for x in range(0, block_dim_x, 16):
            idx = bid * block_dim_x + tid * 16 + x
            if idx < n:
                smem_A[y, x] = A[bid * m + y, idx]

    # Reduction step
    for y in range(block_dim_y):
        max_val = fx.Float32(float("-inf"))
        for x in range(block_dim_x):
            max_val = fx.max(max_val, smem_A[y, x])
        for x in range(block_dim_x):
            smem_A[y, x] -= max_val

    # Softmax computation
    for y in range(block_dim_y):
        sum_exp = fx.Float32(0.0)
        for x in range(block_dim_x):
            sum_exp += fx.exp(smem_A[y, x])
        for x in range(block_dim_x):
            smem_A[y, x] = fx.exp(smem_A[y, x]) / sum_exp

    # Store result back to global memory
    for y in range(0, block_dim_y, 16):
        for x in range(0, block_dim_x, 16):
            idx = bid * block_dim_x + tid * 16 + x
            if idx < n:
                B[bid * m + y, idx] = smem_A[y, x]


@flyc.kernel
def softmax_launcher(A: fx.Tensor, B: fx.Tensor, m: fx.Constexpr[int], n: fx.Constexpr[int]):
    block_dim_x = 256
    block_dim_y = 32
    grid_dim_x = (n + block_dim_x - 1) // block_dim_x
    grid_dim_y = 1

    softmax_kernel[A, (grid_dim_x, grid_dim_y), (block_dim_x, block_dim_y)](A, B, m, n, block_dim_x, block_dim_y)

    return B

import flydsl.compiler as flyc
import flydsl.expr as fx
from flydsl.expr import arith, buffer_ops, const_expr, gpu, range_constexpr
from flydsl.utils.smem_allocator import SmemAllocator

@flyc.jit
def _softmax(
    A: fx.Tensor,
    B: fx.Tensor,
    N: fx.Constexpr[int],
    M: fx.Constexpr[int],
    BLOCK_SIZE: fx.Constexpr[int],
    BLOCKS: fx.Constexpr[int],
):
    tid = gpu.thread_idx.x
    bid = gpu.block_idx.x
    lane = tid % BLOCK_SIZE
    warp_id = tid // BLOCK_SIZE
    smem = SmemAllocator()
    smem_A = smem.alloc((BLOCKS, BLOCK_SIZE), A.dtype)
    smem_B = smem.alloc((BLOCKS, BLOCK_SIZE), A.dtype)
    smem_exp_sum = smem.alloc((BLOCKS,), fx.float32)

    def load_block(data, smem, bid, lane):
        for i in range_constexpr(BLOCKS):
            if bid * BLOCKS + i < M:
                smem[i, lane] = data[bid * BLOCKS + i, lane]
            else:
                smem[i, lane] = const_expr(0.0, data.dtype)

    def store_block(data, smem, bid, lane):
        for i in range_constexpr(BLOCKS):
            if bid * BLOCKS + i < M:
                data[bid * BLOCKS + i, lane] = smem[i, lane]

    def reduce_exp_sum():
        exp_sum = const_expr(0.0, fx.float32)
        for i in range_constexpr(BLOCKS):
            exp_sum += fx.cast(fx.float32, smem_exp_sum[i])
        return exp_sum

    def softmax_warp(smem_A, smem_exp_sum, bid, lane):
        max_val = const_expr(-float('inf'), fx.float32)
        for i in range_constexpr(BLOCKS):
            max_val = fx.max(max_val, fx.cast(fx.float32, smem_A[i, lane]))

        exp_sum = const_expr(0.0, fx.float32)
        for i in range_constexpr(BLOCKS):
            exp_val = fx.exp(fx.cast(fx.float32, smem_A[i, lane]) - max_val)
            smem_exp_sum[i] = exp_val
            exp_sum += exp_val

        for i in range_constexpr(BLOCKS):
            smem_B[i, lane] = fx.cast(A.dtype, smem_exp_sum[i] / exp_sum)

    load_block(A, smem_A, bid, lane)
    softmax_warp(smem_A, smem_exp_sum, bid, lane)
    store_block(B, smem_B, bid, lane)


@flyc.kernel
def softmax_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    N: fx.Constexpr[int],
    M: fx.Constexpr[int],
    BLOCK_SIZE: fx.Constexpr[int],
    BLOCKS: fx.Constexpr[int],
):
    _softmax(A, B, N, M, BLOCK_SIZE, BLOCKS)

@flyc.jit
def softmax_launch(N, M, BLOCK_SIZE, BLOCKS):
    _softmax.kernel[(N,), (M,)](A, B, N, M, BLOCK_SIZE, BLOCKS)

@flyc.jit
def softmax_jit(N, M, BLOCK_SIZE, BLOCKS):
    return _softmax.jit(N, M, BLOCK_SIZE, BLOCKS)

import flydsl.compiler as flyc
import flydsl.expr as fx


@flyc.kernel
def softmax_kernel(
    A: fx.Tensor,
    C: fx.Tensor,
    N: fx.Constexpr[int],
    M: fx.Constexpr[int],
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x

    smem_allocator = fx.SmemAllocator()
    A_smem = smem_allocator.alloc((N, M), A.dtype)
    C_smem = smem_allocator.alloc((N, M), C.dtype)
    smem_allocator.commit()

    for i in range(0, N, fx.constexpr(BLOCK_SIZE)):
        if tid < fx.constexpr(BLOCK_SIZE):
            A_smem[tid, bid] = A[i + tid, bid]

    fx.block_sync()

    max_val = A_smem[tid, bid]
    for i in range(1, fx.constexpr(BLOCK_SIZE)):
        max_val = fx.max(max_val, A_smem[tid, bid + i * fx.constexpr(BLOCK_SIZE)])

    fx.block_sync()

    if tid == 0:
        for i in range(1, fx.constexpr(BLOCK_SIZE)):
            max_val = fx.max(max_val, A_smem[tid, bid + i * fx.constexpr(BLOCK_SIZE)])

    fx.block_sync()

    if tid < fx.constexpr(BLOCK_SIZE):
        A_smem[tid, bid] = A_smem[tid, bid] - max_val

    fx.block_sync()

    sum_val = fx.float32(0.0)
    for i in range(0, fx.constexpr(BLOCK_SIZE), fx.constexpr(WARP_SIZE)):
        sum_val += fx.exp(A_smem[tid, bid + i * fx.constexpr(WARP_SIZE)])

    fx.block_sync()

    if tid == 0:
        for i in range(1, fx.constexpr(BLOCK_SIZE)):
            sum_val += fx.exp(A_smem[tid, bid + i * fx.constexpr(BLOCK_SIZE)])

    fx.block_sync()

    if tid < fx.constexpr(BLOCK_SIZE):
        C_smem[tid, bid] = fx.exp(A_smem[tid, bid]) / sum_val

    fx.block_sync()

    if tid < fx.constexpr(BLOCK_SIZE):
        C[i + tid, bid] = C_smem[tid, bid]


@flyc.jit
def softmax_launch(A, C, N, M):
    block_dim = (fx.constexpr(BLOCK_SIZE), 1, 1)
    grid_dim = (fx.ceil_div(N, fx.constexpr(BLOCK_SIZE)), 1, 1)
    softmax_kernel[grid_dim, block_dim](A, C, N, M)

