BLOCK_N = 64


@flyc.kernel
def topk_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    M: fx.Int32,
    N: fx.Int32,
    K: fx.Int32,
    block_id_x: fx.Int32,
    block_id_y: fx.Int32,
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x

    allocator = SmemAllocator()
    smem_A = allocator.alloc((BLOCK_M, BLOCK_K), fx.Float32)
    smem_B = allocator.alloc((BLOCK_K, BLOCK_N), fx.Float32)
    smem_C = allocator.alloc((BLOCK_M, BLOCK_N), fx.Float32)

    @fx.block
    def compute():
        m = bid * BLOCK_M + tid
        k = bid * BLOCK_K
        n = bid * BLOCK_N

        A_ptr = A.data + m * K + k
        B_ptr = B.data + k * N + n
        C_ptr = B.data + m * N + n

        A_val = fx.float32(0.0)
        B_val = fx.float32(0.0)
        C_val = fx.float32(0.0)

        for i in range_constexpr(BLOCK_K):
            A_val = A_ptr[i]
            B_val = B_ptr[i * BLOCK_N]
            C_val = fx.max(C_val, fx.mul(A_val, B_val))

        buffer_ops.buffer_store(C_ptr, C_val)

    @fx.block
    def load_A():
        for i in range_constexpr(BLOCK_M):
            for j in range_constexpr(BLOCK_K):
                smem_A[i, j] = A[block_id_x * BLOCK_M + i, block_id_y * BLOCK_K + j]

    @fx.block
    def load_B():
        for i in range_constexpr(BLOCK_K):
            for j in range_constexpr(BLOCK_N):
                smem_B[i, j] = B[block_id_y * BLOCK_K + i, block_id_x * BLOCK_N + j]

    @fx.block
    def store_C():
        for i in range_constexpr(BLOCK_M):
            for j in range_constexpr(BLOCK_N):
                B[block_id_x * BLOCK_M + i, block_id_y * BLOCK_N + j] = smem_C[i, j]

    @fx.block
    def load_compute_store():
        for i in range_constexpr(BLOCK_M):
            for j in range_constexpr(BLOCK_N):
                for k in range_constexpr(BLOCK_K):
                    smem_C[i, j] = fx.max(
                        smem_C[i, j], fx.mul(smem_A[i, k], smem_B[k, j])
                    )

    @fx.block
    def pipeline_stage():
        load_A()
        load_B()
        compute()
        store_C()

    pipeline_stage()


def compile_topk(M, N, K):
    stream = gpu.Stream(0)
    kernel = flyc.build(topk_kernel, (M, N, K))
    return kernel

