def kernel_log_softmax(
    A: fx.Tensor,
    C: fx.Tensor,
    M: fx.Int32,
    N: fx.Int32,
) -> None:
    tid = gpu.thread_idx.x
    bid = gpu.block_idx.x
    M_blk = const_expr(A.layout.size(0))
    N_blk = const_expr(A.layout.size(1))
    m = bid * M_blk + tid
    if m < M:
        max_val = fx.Float32(-float("inf"))
        for n in range(N):
            c = A[m, n]
            max_val = fx.max(max_val, c)
        exp_sum = fx.Float32(0.0)
        for n in range(N):
            c = A[m, n]
            exp_c = fx.exp(c - max_val)
            C[m, n] = exp_c
            exp_sum += exp_c
        log_sum = fx.log(exp_sum)
        for n in range(N):
            C[m, n] = c - max_val - log_sum


