@flyc.jit
def add_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    C: fx.Tensor,
    N: fx.Constexpr[int],
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    i = bid * 256 + tid

    if i < N:
        C[i] = A[i] + B[i]


@flyc.jit
def smem_reduce_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    N: fx.Constexpr[int],
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    i = bid * 256 + tid

    smem = fx.SharedAllocator()
    sA = smem.alloc((256,), fx.float32)

    if i < N:
        sA[tid] = A[i]
        fx.syncthreads()

        for stride in range(128, 0, -1):
            if tid < stride:
                sA[tid] += sA[tid + stride]
            fx.syncthreads()

        if tid == 0:
            B[bid] = sA[0]


@flyc.jit
def warp_reduce_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    N: fx.Constexpr[int],
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    i = bid * 256 + tid

    if i < N:
        val = A[i]

        for stride in range(16, 0, -1):
            val += fx.shfl_xor(val, stride)

        if tid % 32 == 0:
            B[bid * 32 + tid // 32] = val

