@flyc.kernel
def topk_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    N: fx.Constexpr[int],
    K: fx.Constexpr[int],
) -> None:
    tid = fx.thread_idx.x
    bid = fx.block_idx.x
    lds = fx.smem_allocator(K * N, fx.DataType.f32)
    for ii in range(N):
        a = A[ii]
        b = B[ii]
        res = topk_jit(a, K)
        lds[ii * K : (ii + 1) * K] = res
    fx.commit_group()

