import flydsl.compiler as flyc
import flydsl.expr as fx
from flydsl.expr import arith, buffer_ops, const_expr, gpu, range_constexpr, rocdl, vector
from flydsl.utils.smem_allocator import SmemAllocator


@flyc.kernel
def moe_gemm_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    C: fx.Tensor,
    M: fx.Int32,
    N: fx.Int32,
    K: fx.Int32,
    stride_a: fx.Int32,
    stride_b: fx.Int32,
    stride_c: fx.Int32,
):
    # Kernel parameters and constants
    BLOCK_M = 128
    BLOCK_N = 128
    BLOCK_K = 32
    TILE_M = 32
    TILE_N = 32

    bidm = gpu.block_id("m")
    bidn = gpu.block_id("n")
    lane_id = gpu.lane_id()

    smem = SmemAllocator()
    shared_A = smem.alloc((BLOCK_M, BLOCK_K), fx.F16)
    shared_B = smem.alloc((BLOCK_K, BLOCK_N), fx.F16)

    c_frag = fx.Tensor.empty((TILE_M, TILE_N), fx.F32)

    # Main loop over K dimension
    for kk in range(0, K, BLOCK_K):
        # Load A into shared memory
        for i in range(0, BLOCK_M, TILE_M):
            for j in range(0, BLOCK_K, TILE_N):
                if bidm * BLOCK_M + i < M and kk + j < K:
                    shared_A[bidm * BLOCK_M + i, kk + j] = A[
                        bidm * BLOCK_M + i, kk + j, stride_a
                    ]
        # Load B into shared memory
        for i in range(0, BLOCK_K, TILE_M):
            for j in range(0, BLOCK_N, TILE_N):
                if kk + i < K and bidn * BLOCK_N + j < N:
                    shared_B[kk + i, bidn * BLOCK_N + j] = B[
                        kk + i, bidn * BLOCK_N + j, stride_b
                    ]

        # Synchronization barrier
        gpu.syncthreads()

        # Compute C = A * B
        for i in range(0, TILE_M):
            for j in range(0, TILE_N):
                c_frag[i, j] = fx.Float32(0.0)
        for k in range(0, BLOCK_K):
            for i in range(0, TILE_M):
                for j in range(0, TILE_N):
                    c_frag[i, j] += fx.Float32(shared_A[bidm * BLOCK_M + i, k]) * fx.Float32(
                        shared_B[k, bidn * BLOCK_N + j]
                    )

        # Synchronization barrier
        gpu.syncthreads()

    # Store C back to global memory
    for i in range(0, TILE_M):
        for j in range(0, TILE_N):
            if bidm * BLOCK_M + i < M and bidn * BLOCK_N + j < N:
                C[bidm * BLOCK_M + i, bidn * BLOCK_N + j, stride_c] = fx.Float16(c_frag[i, j])
    gpu.syncthreads()

