import flydsl.compiler as flyc
import flydsl.expr as fx


@flyc.kernel
def topk_select(
    A: fx.Tensor,
    B: fx.Tensor,
    k: fx.Constexpr[int],
    N: fx.Constexpr[int],
):
    tid = fx.thread_idx.x
    bid = fx.block_idx.x
    block_offset = bid * 256
    tile_size = 128
    smem = fx.SharedMemory(float32, (256, 32))
    smem_ptr = smem.data.cast("float*")

    def load_A(idx):
        return fx.load(A, idx)

    def store_B(idx, val):
        fx.store(B, idx, val)

    for i in range(0, N, tile_size):
        tile = fx.make_range(i, min(i + tile_size, N))
        for j in tile:
            val = load_A(block_offset + tid + j)
            fx.wmma.store_matrix(smem_ptr, val, tid, j - i)

        fx.syncthreads()

        for j in tile:
            val = fx.wmma.load_matrix(smem_ptr, tid, j - i)
            fx.wmma.atomic_max(B, block_offset + tid + j, val)

        fx.syncthreads()


@flyc.jit
def topk_select_jit(A, B, k, N):
    topk_select(A, B, k, N)


def topk_select_launcher(A, B, k, N, stream=0):
    grid = (N + 255) // 256
    block = 256
    topk_select_jit[grid, block, stream](A, B, k, N)


