@flyc.kernel
def rmsnorm(
    out: fx.Tensor,
    inp: fx.Tensor,
    w: fx.Tensor,
    rows: fx.Constexpr[int],
    cols: fx.Constexpr[int],
    nthreads: fx.Constexpr[int],
):
    tid = gpu.thread_idx.x
    bid = gpu.block_idx.x
    smem = SmemAllocator()
    smem_w = smem.alloc((32, 32), fx.Dtype.f32)
    smem_i = smem.alloc((32, 32), fx.Dtype.f32)

    # Load weight into shared memory
    @fx.block
    def load_weight():
        for i in range_constexpr(0, 32):
            smem_w[i, tid] = w[bid * 32 + i, tid]
    rocdl.barrier()

    # Compute partial sums
    @fx.block
    def compute_partial_sums():
        sum_i = 0.0
        for i in range_constexpr(0, 32):
            for j in range_constexpr(0, 32):
                inp_val = inp[bid * 32 + i, tid * 32 + j]
                sum_i += inp_val * inp_val
        smem_i[tid, tid] = sum_i
    rocdl.barrier()

    # Reduce partial sums
    @fx.block
    def reduce_partial_sums():
        for i in range_constexpr(0, 32):
            smem_i[tid, tid] += smem_i[tid, tid + i]
    rocdl.barrier()

    # Compute RMSNorm
    @fx.block
    def compute_rmsnorm():
        denom = smem_i[tid, tid] + 1e-5
        denom = denom.sqrt()
        for i in range_constexpr(0, 32):
            for j in range_constexpr(0, 32):
                inp_val = inp[bid * 32 + i, tid * 32 + j]
                out_val = inp_val / denom
                out[bid * 32 + i, tid * 32 + j] = out_val * smem_w[i, tid]
    rocdl.barrier()


