import flydsl.compiler as flyc
import flydsl.expr as fx
from flydsl.expr import arith, buffer_ops, const_expr, gpu, range_constexpr, rocdl, vector


@flyc.kernel
def kernel_gemm_moe(
    A: fx.Tensor,
    B: fx.Tensor,
    C: fx.Tensor,
    num_experts: fx.Int32,
    expert_ids: fx.Tensor,
):
    bid = gpu.block_idx.x
    tid = gpu.thread_idx.x

    tile_m = 16
    tile_n = 64
    tile_k = 32
    num_warps = 4

    block_id = bid % num_experts
    warp_id = tid // 32
    lane_id = tid % 32

    smem = fx.SmemAllocator()
    smem_A = smem.alloc([tile_m, tile_k], A.dtype)
    smem_B = smem.alloc([tile_k, tile_n], B.dtype)
    gpu.syncthreads()

    C_frag = fx.Tensor.empty((tile_m, tile_n), C.dtype)
    C_frag.fill(0.0)

    for k in range_constexpr(0, A.shape[2], tile_k):
        # Load A and B tiles into shared memory
        for i in range_constexpr(0, tile_m):
            for j in range_constexpr(0, tile_k):
                smem_A[i, j] = A[bid, i, k + j]

        for i in range_constexpr(0, tile_k):
            for j in range_constexpr(0, tile_n):
                smem_B[i, j] = B[bid, i, j]

        gpu.syncthreads()

        # Perform matrix multiply on tiles
        for k_inner in range_constexpr(0, tile_k):
            for i in range_constexpr(0, tile_m):
                for j in range_constexpr(0, tile_n):
                    C_frag[i, j] += smem_A[i, k_inner] * smem_B[k_inner, j]

        gpu.syncthreads()

    # Write results to global memory
    for i in range_constexpr(0, tile_m):
        for j in range_constexpr(0, tile_n):
            C[bid, i, j] = C_frag[i, j]


def compile_gemm_moe_kernel():
    return flyc.compile(kernel_gemm_moe, use_extern_kernel=True)


if __name__ == "__main__":
    compiled_kernel = compile_gemm_moe_kernel()
    print(compiled_kernel.get_source())

import flydsl.compiler as flyc
import flydsl.expr as fx


@flyc.jit
def rope_kernel(
    input: fx.Tensor,
    output: fx.Tensor,
    sin_cache: fx.Tensor,
    cos_cache: fx.Tensor,
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    lane = tid % 32

    smem = flyc.smem_allocator().allocate([16, 64], fx.int32)
    smem_layout = fx.make_layout([16, 64], [64, 1])

    for i in range(64):
        smem[smem_layout(i, lane)] = input[bid, i, lane]

    for i in range(64):
        idx = i // 2
        sin_val = sin_cache[bid, idx]
        cos_val = cos_cache[bid, idx]
        if i % 2 == 0:
            output[bid, i, lane] = smem[smem_layout(i, lane)] * cos_val - smem[
                smem_layout(i + 1, lane)
            ] * sin_val
        else:
            output[bid, i, lane] = smem[smem_layout(i - 1, lane)] * sin_val + smem[
                smem_layout(i, lane)
            ] * cos_val


