import torch

import flydsl.compiler as flyc
import flydsl.expr as fx


@flyc.kernel
def gemm_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    C: fx.Tensor,
    N: fx.Constexpr[int],
    M: fx.Constexpr[int],
    K: fx.Constexpr[int],
):
    tid = fx.thread_idx.x
    bid = fx.block_idx.x

    def get_block_offset(n, m):
        return n * M + m

    def get_thread_offset(n, m):
        return n * M + m

    def get_global_offset(n, m):
        return bid * N * M + n * M + m

    def load_A(n, m):
        return A[get_global_offset(n, m)]

    def load_B(n, m):
        return B[get_global_offset(n, m)]

    def store_C(n, m, value):
        C[get_global_offset(n, m)] = value

    def compute_C(n, m):
        acc = fx.float32(0.0)
        for k in range(K):
            a = load_A(n, k)
            b = load_B(k, m)
            acc += a * b
        return acc

    for n in range(N):
        for m in range(M):
            c = compute_C(n, m)
            store_C(n, m, c)


def gemm(A, B, C):
    N, M, K = A.shape[0], A.shape[1], B.shape[1]
    grid = (1, 1, 1)
    block = (1, 1, 1)
    gemm_kernel.launch(A, B, C, N, M, K, grid=grid, block=block)


