import flydsl.compiler as flyc
import flydsl.expr as fx

@flyc.kernel
def gemm_kernel(
    A: fx.Tensor, B: fx.Tensor, C: fx.Tensor, N: fx.Int32, K: fx.Int32
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    tile_m = 128
    tile_n = 128
    tile_k = 32
    num_tiles = (N + tile_n - 1) // tile_n
    offset_n = bid * tile_n

    smem_allocator = flyc.SmemAllocator()
    smem_A = smem_allocator.tensor([tile_m, tile_k], fx.float16)
    smem_B = smem_allocator.tensor([tile_k, tile_n], fx.float16)
    flyc.smem_declare(smem_allocator)

    C_frag = fx.zeros([tile_m, tile_n], fx.float32)
    for k in range(0, K, tile_k):
        for i in range(tile_m):
            for j in range(tile_k):
                smem_A[i, j] = A[offset_n + bid * tile_n + i, k + j]
        for i in range(tile_k):
            for j in range(tile_n):
                smem_B[i, j] = B[k + i, offset_n + bid * tile_n + j]
        flyc.barrier()

        for i in range(tile_m):
            for j in range(tile_n):
                for k_idx in range(tile_k):
                    C_frag[i, j] += smem_A[i, k_idx] * smem_B[k_idx, j]
        flyc.barrier()

    for i in range(tile_m):
        for j in range(tile_n):
            C[offset_n + bid * tile_n + i, offset_n + bid * tile_n + j] = C_frag[i, j]

